import { useMemo, useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { spaces } from '../data/spaces';

function useFavorites() {
  const [fav, setFav] = useState(() => {
    try {
      const raw = localStorage.getItem('wn:favorites');
      return raw ? JSON.parse(raw) : [];
    } catch {
      return [];
    }
  });
  useEffect(() => {
    localStorage.setItem('wn:favorites', JSON.stringify(fav));
  }, [fav]);
  const toggle = (id) => setFav((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]));
  return { favorites: fav, toggle };
}

export default function Details() {
  const { id } = useParams();
  const space = useMemo(() => spaces.find((s) => s.id === id), [id]);
  const { favorites, toggle } = useFavorites();
  const isFav = favorites.includes(id);

  if (!space) {
    return (
      <div className="min-h-screen flex flex-col bg-white">
        <Navbar />
        <main className="flex-1 max-w-3xl mx-auto px-6 py-16 text-center">
          <h1 className="text-2xl font-bold text-gray-900">Space not found</h1>
          <p className="mt-2 text-gray-600">The workspace you are looking for does not exist.</p>
          <a href="/search" className="mt-6 inline-flex items-center justify-center h-11 px-6 rounded-lg bg-brand-600 text-white font-semibold hover:bg-brand-700 transition">Back to search</a>
        </main>
        <Footer />
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1 max-w-7xl mx-auto px-6 py-10">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2">
            <div className="aspect-video rounded-2xl bg-gradient-to-br from-brand-100 to-brand-300" />
            <div className="mt-6 flex items-start justify-between gap-4">
              <div>
                <h1 className="text-3xl font-bold text-gray-900">{space.name}</h1>
                <p className="mt-2 text-gray-600">{space.locationText} • ★ {space.rating}</p>
              </div>
              <button
                type="button"
                className={`text-sm px-3 py-2 rounded-lg border ${isFav ? 'border-brand-600 text-brand-700 bg-brand-50' : 'border-gray-200 text-gray-700 hover:border-brand-300'}`}
                onClick={() => toggle(space.id)}
              >
                {isFav ? '★ Saved' : '☆ Save'}
              </button>
            </div>
            <div className="mt-6 space-y-3">
              <div className="text-gray-900 font-semibold">Amenities</div>
              <div className="flex flex-wrap gap-2">
                {space.amenities.map((a) => (
                  <span key={a} className="text-xs px-2 py-1 rounded-full bg-gray-100 text-gray-700">{a}</span>
                ))}
              </div>
            </div>
          </div>
          <aside className="lg:col-span-1">
            <div className="p-6 rounded-2xl border border-gray-100 shadow-card">
              <div className="text-2xl font-bold text-gray-900">₹{space.pricePerDay}<span className="text-base font-medium text-gray-500">/day</span></div>
              <div className="mt-3 grid grid-cols-2 gap-3">
                <select className="h-11 px-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-400" defaultValue={space.type}>
                  <option>Hot Desk</option>
                  <option>Dedicated Desk</option>
                  <option>Private Office</option>
                  <option>Meeting Room</option>
                </select>
                <input type="date" className="h-11 px-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-brand-400" />
              </div>
              <button className="mt-4 w-full h-11 rounded-lg bg-brand-600 text-white font-semibold hover:bg-brand-700 transition">Book Now</button>
              <p className="mt-3 text-xs text-gray-500">Secure payment • Auto agreement generated</p>
              <div className="mt-4 text-sm text-gray-600">
                <div>Owner: {space.owner.name}</div>
                <div className="text-gray-500">Contact: {space.owner.phone}</div>
              </div>
            </div>
          </aside>
        </div>
      </main>
      <Footer />
    </div>
  );
}
